Using Object.assign or spread operators to directly merge request body data with database models is extremely dangerous. This pattern, known as mass assignment, allows attackers to modify any field including sensitive ones like roles, permissions, and account status.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

const UserSchema = new mongoose.Schema({
  username: String,
  email: String,
  password: String,
  role: { type: String, default: 'user' },
  isAdmin: { type: Boolean, default: false },
  accountBalance: { type: Number, default: 0 },
  verified: { type: Boolean, default: false }
});

const User = mongoose.model('User', UserSchema);

// VULNERABLE: Directly merging request body
app.put('/api/users/:id', async (req, res) => {
  try {
    const user = await User.findById(req.params.id);
    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }

    // DANGER: Any field from request body gets assigned
    Object.assign(user, req.body);
    await user.save();

    res.json({ message: 'Profile updated', user });
  } catch (error) {
    res.status(500).json({ error: 'Update failed' });
  }
});
```

**Attack Payload**:
```json
{
  "username": "legituser",
  "email": "user@example.com",
  "role": "admin",
  "isAdmin": true,
  "accountBalance": 999999,
  "verified": true
}
```

**Why This Is Dangerous**:
- Attackers can escalate privileges by setting `role: 'admin'` or `isAdmin: true`
- Financial fraud possible by modifying `accountBalance`
- Bypass verification requirements by setting `verified: true`
- Can potentially modify password hashes if they're in the same model

**SECURE VERSION**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const { body, validationResult } = require('express-validator');

const app = express();
app.use(express.json());

const User = mongoose.model('User', UserSchema);

// Define explicit allowlists for different operations
const ALLOWED_USER_UPDATE_FIELDS = ['username', 'email', 'bio', 'avatar'];
const ALLOWED_ADMIN_UPDATE_FIELDS = [...ALLOWED_USER_UPDATE_FIELDS, 'role', 'isAdmin', 'verified'];

// Helper function to pick only allowed fields
function pickAllowedFields(source, allowedFields) {
  const result = {};
  for (const field of allowedFields) {
    if (source.hasOwnProperty(field)) {
      result[field] = source[field];
    }
  }
  return result;
}

// SECURE: Explicit field allowlisting
app.put('/api/users/:id',
  [
    body('username').optional().isLength({ min: 3, max: 30 }).trim().escape(),
    body('email').optional().isEmail().normalizeEmail(),
    body('bio').optional().isLength({ max: 500 }).trim()
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    try {
      const user = await User.findById(req.params.id);
      if (!user) {
        return res.status(404).json({ error: 'User not found' });
      }

      // Verify user can only update their own profile
      if (user._id.toString() !== req.user.id) {
        return res.status(403).json({ error: 'Forbidden' });
      }

      // SECURE: Only allow specific fields
      const allowedUpdates = pickAllowedFields(req.body, ALLOWED_USER_UPDATE_FIELDS);

      // Apply updates field by field
      Object.assign(user, allowedUpdates);
      await user.save();

      res.json({ message: 'Profile updated successfully' });
    } catch (error) {
      console.error('Update error:', error);
      res.status(500).json({ error: 'Update failed' });
    }
  }
);
```

**Key Security Controls**:
- **Explicit Allowlisting**: Only pre-approved fields can be modified, any extra fields are silently ignored
- **Input Validation**: Each field is validated for type, length, and format using express-validator
- **Authorization Check**: Verifies the user can only modify their own profile

Excellent question! Role-based field access requires a robust permission system with defense in depth. Here's a production-ready pattern that handles different roles with proper audit logging and rate limiting.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const { body, param, validationResult } = require('express-validator');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();
app.use(express.json());

// Production-ready logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'audit.log' }),
    new winston.transports.File({ filename: 'security.log', level: 'warn' })
  ]
});

// Role-based field permissions matrix
const FIELD_PERMISSIONS = {
  user: {
    self: ['username', 'email', 'bio', 'avatar', 'notifications'],
    others: [] // Users cannot modify other users
  },
  moderator: {
    self: ['username', 'email', 'bio', 'avatar', 'notifications'],
    others: ['bio', 'avatar'] // Can edit basic profile info of others
  },
  admin: {
    self: ['username', 'email', 'bio', 'avatar', 'notifications', 'role'],
    others: ['username', 'email', 'bio', 'avatar', 'verified', 'suspended']
  },
  superadmin: {
    self: ['username', 'email', 'bio', 'avatar', 'notifications', 'role'],
    others: ['username', 'email', 'bio', 'avatar', 'verified', 'suspended', 'role', 'isAdmin']
  }
};

// Fields that should NEVER be mass-assignable
const PROTECTED_FIELDS = ['_id', 'password', 'passwordHash', 'accountBalance', 'createdAt', 'lastLogin', 'apiKey', 'secretToken'];

// Field validation rules
const FIELD_VALIDATORS = {
  username: body('username').optional().isLength({ min: 3, max: 30 }).trim().matches(/^[a-zA-Z0-9_]+$/),
  email: body('email').optional().isEmail().normalizeEmail(),
  bio: body('bio').optional().isLength({ max: 500 }).trim(),
  avatar: body('avatar').optional().isURL({ protocols: ['https'] }),
  notifications: body('notifications').optional().isBoolean(),
  role: body('role').optional().isIn(['user', 'moderator', 'admin']),
  verified: body('verified').optional().isBoolean(),
  suspended: body('suspended').optional().isBoolean(),
  isAdmin: body('isAdmin').optional().isBoolean()
};

// Rate limiting for profile updates
const updateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // 10 updates per window
  message: { error: 'Too many update requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Get allowed fields based on role and target
function getAllowedFields(actorRole, isSelf) {
  const permissions = FIELD_PERMISSIONS[actorRole];
  if (!permissions) {
    return [];
  }
  return isSelf ? permissions.self : permissions.others;
}

// Secure field picker with audit trail
function pickAllowedFields(source, allowedFields, protectedFields) {
  const result = {};
  const rejected = [];

  for (const [key, value] of Object.entries(source)) {
    if (protectedFields.includes(key)) {
      rejected.push({ field: key, reason: 'protected' });
      continue;
    }
    if (allowedFields.includes(key)) {
      result[key] = value;
    } else {
      rejected.push({ field: key, reason: 'not_permitted' });
    }
  }

  return { allowed: result, rejected };
}

// Dynamic validator middleware
function createFieldValidators(requestedFields) {
  return Object.keys(requestedFields)
    .filter(field => FIELD_VALIDATORS[field])
    .map(field => FIELD_VALIDATORS[field]);
}

// Authentication middleware (assumes JWT or session)
const authenticate = async (req, res, next) => {
  // Implementation depends on your auth strategy
  // req.user should contain { id, role }
  if (!req.user) {
    return res.status(401).json({ error: 'Authentication required' });
  }
  next();
};

// PRODUCTION SECURE ENDPOINT
app.put('/api/users/:id',
  authenticate,
  updateLimiter,
  param('id').isMongoId(),
  async (req, res) => {
    // Validate param
    const paramErrors = validationResult(req);
    if (!paramErrors.isEmpty()) {
      return res.status(400).json({ errors: paramErrors.array() });
    }

    const targetUserId = req.params.id;
    const actorId = req.user.id;
    const actorRole = req.user.role;
    const isSelf = targetUserId === actorId;

    // Get allowed fields for this actor/target combination
    const allowedFields = getAllowedFields(actorRole, isSelf);

    if (allowedFields.length === 0 && !isSelf) {
      logger.warn({
        event: 'unauthorized_update_attempt',
        actor: actorId,
        target: targetUserId,
        role: actorRole,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });
      return res.status(403).json({ error: 'You cannot modify this user' });
    }

    // Pick only allowed fields
    const { allowed: updates, rejected } = pickAllowedFields(
      req.body,
      allowedFields,
      PROTECTED_FIELDS
    );

    // Log any rejected field attempts (potential attack indicator)
    if (rejected.length > 0) {
      logger.warn({
        event: 'mass_assignment_attempt',
        actor: actorId,
        target: targetUserId,
        rejectedFields: rejected,
        ip: req.ip,
        userAgent: req.get('User-Agent'),
        timestamp: new Date().toISOString()
      });
    }

    // Run validators for allowed fields only
    const validators = createFieldValidators(updates);
    await Promise.all(validators.map(v => v.run(req)));

    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    try {
      // Use atomic update with explicit $set
      const result = await User.findByIdAndUpdate(
        targetUserId,
        { $set: updates },
        { new: true, runValidators: true }
      ).select('-password -passwordHash -apiKey');

      if (!result) {
        return res.status(404).json({ error: 'User not found' });
      }

      // Audit log successful update
      logger.info({
        event: 'user_updated',
        actor: actorId,
        actorRole: actorRole,
        target: targetUserId,
        fieldsModified: Object.keys(updates),
        isSelf,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });

      res.json({
        message: 'User updated successfully',
        user: result
      });
    } catch (error) {
      logger.error({
        event: 'update_error',
        actor: actorId,
        target: targetUserId,
        error: error.message,
        timestamp: new Date().toISOString()
      });
      res.status(500).json({ error: 'Update failed' });
    }
  }
);

// Health check for monitoring
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

module.exports = app;
```

**Defense in Depth Layers**:

1. **Authentication Layer**: Verifies identity before any operation
```javascript
const authenticate = async (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Token required' });
  // Verify JWT and attach user to request
};
```

2. **Role-Based Permission Matrix**: Granular control over who can modify what
```javascript
const FIELD_PERMISSIONS = {
  user: { self: ['username', 'email'], others: [] },
  admin: { self: [...], others: ['verified', 'suspended'] }
};
```

3. **Protected Fields Blocklist**: Additional safety net for critical fields
```javascript
const PROTECTED_FIELDS = ['_id', 'password', 'accountBalance', 'apiKey'];
// These are NEVER modifiable via mass assignment regardless of role
```

**Additional Protections**:

- **Rate Limiting**: Prevents brute-force attempts to find exploitable fields
- **Comprehensive Audit Logging**: Every modification attempt is logged with actor, target, fields, and IP
- **Security Alerting**: Rejected field attempts trigger warnings for security monitoring
- **Input Validation**: Each field type has specific validation rules
- **Atomic Updates**: Using `$set` operator prevents race conditions
- **Response Sanitization**: Sensitive fields excluded from response using `.select()`
- **Mongoose Schema Validators**: Additional validation layer at database level

No, directly binding JSON requests to domain entities is extremely dangerous due to **mass assignment vulnerabilities**. Attackers can inject additional fields in the JSON payload to modify sensitive attributes they shouldn't have access to, like roles or permissions.

**VULNERABLE CODE**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import javax.persistence.*;

@Entity
@Table(name = "users")
public class User {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    private String username;
    private String email;
    private String password;

    // DANGEROUS: These fields can be overwritten via mass assignment
    private String role = "USER";
    private boolean isAdmin = false;
    private boolean isVerified = false;
    private double accountBalance = 0.0;

    // Getters and setters for all fields
    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }
    public String getUsername() { return username; }
    public void setUsername(String username) { this.username = username; }
    public String getEmail() { return email; }
    public void setEmail(String email) { this.email = email; }
    public String getPassword() { return password; }
    public void setPassword(String password) { this.password = password; }
    public String getRole() { return role; }
    public void setRole(String role) { this.role = role; }
    public boolean isAdmin() { return isAdmin; }
    public void setAdmin(boolean admin) { isAdmin = admin; }
    public boolean isVerified() { return isVerified; }
    public void setVerified(boolean verified) { isVerified = verified; }
    public double getAccountBalance() { return accountBalance; }
    public void setAccountBalance(double accountBalance) { this.accountBalance = accountBalance; }
}

@RestController
@RequestMapping("/api/users")
public class UserController {

    @Autowired
    private UserRepository userRepository;

    // VULNERABLE: Direct entity binding allows mass assignment
    @PutMapping("/{id}")
    public User updateUser(@PathVariable Long id, @RequestBody User userUpdate) {
        User existingUser = userRepository.findById(id)
            .orElseThrow(() -> new RuntimeException("User not found"));

        // BeanUtils copies ALL properties from request to entity!
        org.springframework.beans.BeanUtils.copyProperties(userUpdate, existingUser);

        return userRepository.save(existingUser);
    }
}
```

**Attack Payload**:
```json
{
  "username": "john_doe",
  "email": "john@example.com",
  "role": "ADMIN",
  "isAdmin": true,
  "isVerified": true,
  "accountBalance": 999999.99
}
```

**Why This Is Dangerous**:
- Attackers can escalate privileges by setting `role: "ADMIN"` or `isAdmin: true`
- Financial fraud by manipulating `accountBalance` field
- Bypass email verification by setting `isVerified: true`
- Spring's `BeanUtils.copyProperties()` copies ALL matching fields without filtering

**SECURE VERSION**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import javax.validation.Valid;
import javax.validation.constraints.*;

// DTO with ONLY allowed fields - the key defense
public class UserUpdateDTO {
    @Size(min = 3, max = 50, message = "Username must be 3-50 characters")
    private String username;

    @Email(message = "Invalid email format")
    private String email;

    @Size(min = 1, max = 100)
    private String displayName;

    // NO role, isAdmin, isVerified, accountBalance fields!
    // These are intentionally excluded from the DTO

    public String getUsername() { return username; }
    public void setUsername(String username) { this.username = username; }
    public String getEmail() { return email; }
    public void setEmail(String email) { this.email = email; }
    public String getDisplayName() { return displayName; }
    public void setDisplayName(String displayName) { this.displayName = displayName; }
}

@RestController
@RequestMapping("/api/users")
public class SecureUserController {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private AuditLogService auditLogService;

    @PutMapping("/{id}")
    public ResponseEntity<UserResponseDTO> updateUser(
            @PathVariable Long id,
            @Valid @RequestBody UserUpdateDTO updateDTO,
            @AuthenticationPrincipal UserPrincipal currentUser) {

        // Authorization check: users can only update their own profile
        if (!currentUser.getId().equals(id) && !currentUser.hasRole("ADMIN")) {
            auditLogService.logUnauthorizedAccess(currentUser.getId(), id, "UPDATE_USER");
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }

        User existingUser = userRepository.findById(id)
            .orElseThrow(() -> new ResourceNotFoundException("User not found"));

        // EXPLICIT field mapping - only allowed fields are updated
        if (updateDTO.getUsername() != null) {
            existingUser.setUsername(updateDTO.getUsername());
        }
        if (updateDTO.getEmail() != null) {
            existingUser.setEmail(updateDTO.getEmail());
        }
        if (updateDTO.getDisplayName() != null) {
            existingUser.setDisplayName(updateDTO.getDisplayName());
        }

        User savedUser = userRepository.save(existingUser);
        auditLogService.logUserUpdate(currentUser.getId(), id, updateDTO);

        return ResponseEntity.ok(new UserResponseDTO(savedUser));
    }
}
```

**Key Security Controls**:
- **DTO Pattern**: Separate Data Transfer Objects with only permitted fields prevent mass assignment by design
- **Explicit Field Mapping**: Each field is explicitly copied, never automatic bulk copying
- **Authorization Check**: Verifies the authenticated user can only modify their own data
- **Input Validation**: Bean Validation annotations enforce data constraints
- **Audit Logging**: All profile changes are logged for security monitoring

For role-based field access, you need separate DTOs for each permission level combined with a service layer that enforces field-level access control. This is the production-ready approach used by enterprises.

**PRODUCTION PATTERN**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import javax.validation.Valid;
import javax.validation.constraints.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.Set;
import java.util.HashSet;

// Base DTO for regular users - minimal fields
public class UserSelfUpdateDTO {
    @Size(min = 3, max = 50)
    private String username;

    @Email
    private String email;

    @Size(max = 200)
    private String bio;

    // Getters and setters
    public String getUsername() { return username; }
    public void setUsername(String username) { this.username = username; }
    public String getEmail() { return email; }
    public void setEmail(String email) { this.email = email; }
    public String getBio() { return bio; }
    public void setBio(String bio) { this.bio = bio; }
}

// Admin DTO extends base with privileged fields
public class AdminUserUpdateDTO extends UserSelfUpdateDTO {
    @Pattern(regexp = "^(USER|MODERATOR|ADMIN)$")
    private String role;

    private Boolean isVerified;

    private Boolean isActive;

    @PositiveOrZero
    private Double accountBalance;

    // Getters and setters
    public String getRole() { return role; }
    public void setRole(String role) { this.role = role; }
    public Boolean getIsVerified() { return isVerified; }
    public void setIsVerified(Boolean isVerified) { this.isVerified = isVerified; }
    public Boolean getIsActive() { return isActive; }
    public void setIsActive(Boolean isActive) { this.isActive = isActive; }
    public Double getAccountBalance() { return accountBalance; }
    public void setAccountBalance(Double accountBalance) { this.accountBalance = accountBalance; }
}

// Field-level access control service
@Service
public class UserUpdateService {
    private static final Logger logger = LoggerFactory.getLogger(UserUpdateService.class);

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private AuditLogService auditLogService;

    @Autowired
    private SecurityEventPublisher securityEventPublisher;

    // Define allowed fields per role
    private static final Set<String> USER_ALLOWED_FIELDS = Set.of(
        "username", "email", "bio", "displayName"
    );

    private static final Set<String> MODERATOR_ALLOWED_FIELDS = Set.of(
        "username", "email", "bio", "displayName", "isVerified"
    );

    private static final Set<String> ADMIN_ALLOWED_FIELDS = Set.of(
        "username", "email", "bio", "displayName", "role", 
        "isVerified", "isActive", "accountBalance"
    );

    // Blocked fields that can NEVER be mass-assigned
    private static final Set<String> BLOCKED_FIELDS = Set.of(
        "id", "password", "passwordHash", "createdAt", "lastLoginIp",
        "failedLoginAttempts", "mfaSecret", "apiKey", "internalNotes"
    );

    @Transactional
    public User updateUserWithRoleCheck(
            Long targetUserId,
            Object updateDTO,
            UserPrincipal currentUser) {

        User targetUser = userRepository.findById(targetUserId)
            .orElseThrow(() -> new ResourceNotFoundException("User not found"));

        Set<String> allowedFields = getAllowedFieldsForRole(currentUser);
        Set<String> changedFields = new HashSet<>();

        // Apply updates with field-level access control
        if (updateDTO instanceof AdminUserUpdateDTO) {
            AdminUserUpdateDTO adminDTO = (AdminUserUpdateDTO) updateDTO;
            changedFields.addAll(applyAdminUpdates(targetUser, adminDTO, allowedFields, currentUser));
        } else if (updateDTO instanceof UserSelfUpdateDTO) {
            UserSelfUpdateDTO userDTO = (UserSelfUpdateDTO) updateDTO;
            changedFields.addAll(applyUserUpdates(targetUser, userDTO, allowedFields));
        }

        User savedUser = userRepository.save(targetUser);

        // Comprehensive audit logging
        auditLogService.logFieldChanges(
            currentUser.getId(),
            targetUserId,
            changedFields,
            getClientIp()
        );

        // Alert on sensitive field changes
        if (changedFields.contains("role") || changedFields.contains("isAdmin")) {
            securityEventPublisher.publishPrivilegeChangeEvent(
                currentUser.getId(), targetUserId, changedFields
            );
        }

        logger.info("User {} updated user {} fields: {}", 
            currentUser.getId(), targetUserId, changedFields);

        return savedUser;
    }

    private Set<String> getAllowedFieldsForRole(UserPrincipal user) {
        if (user.hasRole("ADMIN")) {
            return ADMIN_ALLOWED_FIELDS;
        } else if (user.hasRole("MODERATOR")) {
            return MODERATOR_ALLOWED_FIELDS;
        }
        return USER_ALLOWED_FIELDS;
    }

    private Set<String> applyAdminUpdates(
            User target, 
            AdminUserUpdateDTO dto, 
            Set<String> allowedFields,
            UserPrincipal admin) {

        Set<String> changed = new HashSet<>();

        // Self-demotion prevention
        if (dto.getRole() != null && 
            target.getId().equals(admin.getId()) && 
            !"ADMIN".equals(dto.getRole())) {
            throw new SecurityException("Admins cannot demote themselves");
        }

        // Apply base user fields first
        changed.addAll(applyUserUpdates(target, dto, allowedFields));

        // Admin-specific fields with explicit checks
        if (dto.getRole() != null && allowedFields.contains("role")) {
            if (!target.getRole().equals(dto.getRole())) {
                changed.add("role");
                target.setRole(dto.getRole());
            }
        }

        if (dto.getIsVerified() != null && allowedFields.contains("isVerified")) {
            if (target.isVerified() != dto.getIsVerified()) {
                changed.add("isVerified");
                target.setVerified(dto.getIsVerified());
            }
        }

        if (dto.getIsActive() != null && allowedFields.contains("isActive")) {
            if (target.isActive() != dto.getIsActive()) {
                changed.add("isActive");
                target.setActive(dto.getIsActive());
            }
        }

        if (dto.getAccountBalance() != null && allowedFields.contains("accountBalance")) {
            if (!target.getAccountBalance().equals(dto.getAccountBalance())) {
                changed.add("accountBalance");
                target.setAccountBalance(dto.getAccountBalance());
            }
        }

        return changed;
    }

    private Set<String> applyUserUpdates(
            User target, 
            UserSelfUpdateDTO dto, 
            Set<String> allowedFields) {

        Set<String> changed = new HashSet<>();

        if (dto.getUsername() != null && allowedFields.contains("username")) {
            if (!dto.getUsername().equals(target.getUsername())) {
                changed.add("username");
                target.setUsername(dto.getUsername());
            }
        }

        if (dto.getEmail() != null && allowedFields.contains("email")) {
            if (!dto.getEmail().equals(target.getEmail())) {
                changed.add("email");
                target.setEmail(dto.getEmail());
            }
        }

        if (dto.getBio() != null && allowedFields.contains("bio")) {
            if (!dto.getBio().equals(target.getBio())) {
                changed.add("bio");
                target.setBio(dto.getBio());
            }
        }

        return changed;
    }
}

// Controller with role-based endpoints
@RestController
@RequestMapping("/api/users")
public class ProductionUserController {

    private static final Logger logger = LoggerFactory.getLogger(ProductionUserController.class);

    @Autowired
    private UserUpdateService userUpdateService;

    @Autowired
    private RateLimiter rateLimiter;

    // Regular user self-update endpoint
    @PutMapping("/me")
    public ResponseEntity<UserResponseDTO> updateSelf(
            @Valid @RequestBody UserSelfUpdateDTO updateDTO,
            @AuthenticationPrincipal UserPrincipal currentUser,
            HttpServletRequest request) {

        if (!rateLimiter.tryAcquire("user-update:" + currentUser.getId())) {
            return ResponseEntity.status(HttpStatus.TOO_MANY_REQUESTS).build();
        }

        User updated = userUpdateService.updateUserWithRoleCheck(
            currentUser.getId(), updateDTO, currentUser
        );

        return ResponseEntity.ok(new UserResponseDTO(updated));
    }

    // Admin endpoint with elevated permissions
    @PutMapping("/{id}")
    @PreAuthorize("hasRole('ADMIN')")
    public ResponseEntity<UserResponseDTO> adminUpdateUser(
            @PathVariable Long id,
            @Valid @RequestBody AdminUserUpdateDTO updateDTO,
            @AuthenticationPrincipal UserPrincipal currentUser,
            HttpServletRequest request) {

        logger.info("Admin {} updating user {} from IP {}", 
            currentUser.getId(), id, request.getRemoteAddr());

        User updated = userUpdateService.updateUserWithRoleCheck(
            id, updateDTO, currentUser
        );

        return ResponseEntity.ok(new UserResponseDTO(updated));
