        'user' => ['username', 'email'],
        'moderator' => ['username', 'email', 'bio', 'avatar'],
        'admin' => ['username', 'email', 'bio', 'avatar', 'is_admin', 'role_id'],
        'super_admin' => ['username', 'email', 'bio', 'avatar', 'is_admin', 'role_id', 'account_balance']
    ];

    // Fields that require additional confirmation
    private const SENSITIVE_FIELDS = ['is_admin', 'role_id', 'account_balance'];

    // Validation rules per field
    private const VALIDATION_RULES = [
        'username' => ['min' => 3, 'max' => 50, 'pattern' => '/^[a-zA-Z0-9_]+$/'],
        'email' => ['type' => 'email', 'max' => 255],
        'is_admin' => ['type' => 'boolean'],
        'role_id' => ['type' => 'integer', 'min' => 1, 'max' => 10],
        'account_balance' => ['type' => 'decimal', 'min' => 0, 'max' => 1000000]
    ];

    public function __construct(PDO $pdo, AuditLogger $auditLogger) {
        $this->pdo = $pdo;
        $this->auditLogger = $auditLogger;
    }

    /**
     * Secure mass assignment with role-based field access
     */
    public function fill(array $data, string $actorRole, int $actorId): self {
        // Get allowed fields for this role
        $allowedFields = $this->getAllowedFields($actorRole);

        // Track attempted violations
        $violations = [];
        $changes = [];

        foreach ($data as $field => $value) {
            // Check if field is allowed for this role
            if (!in_array($field, $allowedFields, true)) {
                $violations[] = $field;
                continue;
            }

            // Validate the value
            $validatedValue = $this->validateField($field, $value);

            // Track changes for audit
            $oldValue = $this->$field ?? null;
            if ($oldValue !== $validatedValue) {
                $changes[$field] = [
                    'old' => $this->maskSensitiveValue($field, $oldValue),
                    'new' => $this->maskSensitiveValue($field, $validatedValue)
                ];
            }

            $this->$field = $validatedValue;
        }

        // Log any attempted mass assignment attacks
        if (!empty($violations)) {
            $this->auditLogger->warning('mass_assignment_attempt', [
                'actor_id' => $actorId,
                'actor_role' => $actorRole,
                'target_user_id' => $this->id,
                'blocked_fields' => $violations,
                'ip_address' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
                'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown'
            ]);

            // Optionally throw exception for strict mode
            if (getenv('MASS_ASSIGNMENT_STRICT') === 'true') {
                throw new MassAssignmentException(
                    "Attempted to assign protected fields: " . implode(', ', $violations)
                );
            }
        }

        // Log successful changes to sensitive fields
        $sensitiveChanges = array_intersect_key($changes, array_flip(self::SENSITIVE_FIELDS));
        if (!empty($sensitiveChanges)) {
            $this->auditLogger->critical('sensitive_field_modification', [
                'actor_id' => $actorId,
                'actor_role' => $actorRole,
                'target_user_id' => $this->id,
                'changes' => $sensitiveChanges,
                'ip_address' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
                'timestamp' => date('c')
            ]);
        }

        return $this;
    }

    private function getAllowedFields(string $role): array {
        if (!isset(self::FILLABLE_BY_ROLE[$role])) {
            return self::FILLABLE_BY_ROLE['user']; // Default to most restrictive
        }
        return self::FILLABLE_BY_ROLE[$role];
    }

    private function validateField(string $field, $value) {
        $rules = self::VALIDATION_RULES[$field] ?? [];

        if (isset($rules['type'])) {
            switch ($rules['type']) {
                case 'email':
                    if (!filter_var($value, FILTER_VALIDATE_EMAIL)) {
                        throw new \InvalidArgumentException("Invalid email format");
                    }
                    return filter_var($value, FILTER_SANITIZE_EMAIL);

                case 'boolean':
                    return filter_var($value, FILTER_VALIDATE_BOOLEAN, FILTER_NULL_ON_FAILURE) ?? false;

                case 'integer':
                    $intVal = filter_var($value, FILTER_VALIDATE_INT);
                    if ($intVal === false) {
                        throw new \InvalidArgumentException("Invalid integer for {$field}");
                    }
                    if (isset($rules['min']) && $intVal < $rules['min']) {
                        throw new \InvalidArgumentException("{$field} must be >= {$rules['min']}");
                    }
                    if (isset($rules['max']) && $intVal > $rules['max']) {
                        throw new \InvalidArgumentException("{$field} must be <= {$rules['max']}");
                    }
                    return $intVal;

                case 'decimal':
                    $floatVal = filter_var($value, FILTER_VALIDATE_FLOAT);
                    if ($floatVal === false) {
                        throw new \InvalidArgumentException("Invalid decimal for {$field}");
                    }
                    return round($floatVal, 2);
            }
        }

        // String validation
        $strValue = trim((string) $value);

        if (isset($rules['min']) && strlen($strValue) < $rules['min']) {
            throw new \InvalidArgumentException("{$field} must be at least {$rules['min']} characters");
        }

        if (isset($rules['max']) && strlen($strValue) > $rules['max']) {
            throw new \InvalidArgumentException("{$field} must not exceed {$rules['max']} characters");
        }

        if (isset($rules['pattern']) && !preg_match($rules['pattern'], $strValue)) {
            throw new \InvalidArgumentException("{$field} contains invalid characters");
        }

        return htmlspecialchars($strValue, ENT_QUOTES, 'UTF-8');
    }

    private function maskSensitiveValue(string $field, $value): string {
        if (in_array($field, ['password', 'api_key', 'secret'], true)) {
            return '[REDACTED]';
        }
        return (string) $value;
    }

    public function save(): bool {
        $this->updated_at = date('Y-m-d H:i:s');

        $sql = "UPDATE users SET 
                    username = :username,
                    email = :email,
                    is_admin = :is_admin,
                    role_id = :role_id,
                    account_balance = :account_balance,
                    updated_at = :updated_at
                WHERE id = :id";

        $stmt = $this->pdo->prepare($sql);
        return $stmt->execute([
            ':username' => $this->username,
            ':email' => $this->email,
            ':is_admin' => $this->is_admin ? 1 : 0,
            ':role_id' => $this->role_id,
            ':account_balance' => $this->account_balance,
            ':updated_at' => $this->updated_at,
            ':id' => $this->id
        ]);
    }
}

// Secure Controller with Authorization
class UserController {
    private PDO $pdo;
    private AuditLogger $auditLogger;
    private RateLimiter $rateLimiter;

    public function updateProfile(Request $request): Response {
        // Rate limiting
        if (!$this->rateLimiter->attempt($request->user()->id, 'profile_update', 10, 3600)) {
            return new Response(['error' => 'Too many update attempts'], 429);
        }

        try {
            $actor = $request->user();
            $targetUserId = (int) $request->input('user_id', $actor->id);

            // Authorization check: Can this actor edit this user?
            if (!$this->canEditUser($actor, $targetUserId)) {
                $this->auditLogger->warning('unauthorized_edit_attempt', [
                    'actor_id' => $actor->id,
                    'target_id' => $targetUserId
                ]);
                return new Response(['error' => 'Unauthorized'], 403);
            }

            $user = User::find($targetUserId);
            $user->fill(
                $request->input(),
                $actor->role,
                $actor->id
            );
            $user->save();

            return new Response(['success' => true, 'message' => 'Profile updated']);

        } catch (MassAssignmentException $e) {
            return new Response(['error' => 'Invalid fields submitted'], 400);
        } catch (\InvalidArgumentException $e) {
            return new Response(['error' => $e->getMessage()], 422);
        } catch (\Exception $e) {
            $this->auditLogger->error('profile_update_failed', [
                'error' => $e->getMessage()
            ]);
            return new Response(['error' => 'Update failed'], 500);
        }
    }

    private function canEditUser($actor, int $targetId): bool {
        // Users can edit themselves
        if ($actor->id === $targetId) {
            return true;
        }
        // Admins can edit anyone
        if (in_array($actor->role, ['admin', 'super_admin'], true)) {
            return true;
        }
        return false;
    }
}
```

