public class UpdateUserBaseDto  // For regular users
{
    public string Username { get; set; }
    public string Email { get; set; }
}

public class AdminUpdateUserDto : UpdateUserBaseDto  // For admins
{
    public bool? IsActive { get; set; }  // Admin-only
    public int? RoleId { get; set; }      // Admin-only
}
```

2. **Attribute-Based Protection with [Bind]**:
```csharp
// Alternative: Explicit binding whitelist
[HttpPut("{id}")]
public async Task<IActionResult> UpdateUser(
    int id,
    [Bind("Username,Email")] User user)  // Only bind these fields
{
    // Even if attacker sends IsAdmin=true, it won't bind
